// Schema验证节点
const schema = {
  required: ['timestamp', 'deviceId', 'data'],
  properties: {
    timestamp: { type: 'string' },
    deviceId: { type: 'string' },
    data: { type: 'object' }
  }
};

// 简化的验证逻辑
const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;
  let isValid = true;
  let errors = [];

  // 检查必填字段
  for (const field of schema.required) {
    if (!data[field]) {
      isValid = false;
      errors.push(`缺少必填字段: ${field}`);
    }
  }

  results.push({
    json: {
      ...data,
      _validation: {
        status: isValid ? 'accepted' : 'rejected',
        errors: errors,
        timestamp: new Date().toISOString()
      }
    }
  });
}

return results;

// 数据清洗节点 - 模拟LLM调用
const items = $input.all();
const cleaned = [];

for (const item of items) {
  const data = item.json;

  // 模拟数据清洗逻辑
  const cleanedData = {
    timestamp: new Date(data.timestamp).toISOString(),
    deviceId: data.deviceId.toUpperCase().trim(),
    data: data.data,
    _cleaning: {
      changes: [],
      confidence: 0.95,
      method: 'rule-based',
      processedAt: new Date().toISOString()
    }
  };

  // 记录清洗变更
  if (data.timestamp !== cleanedData.timestamp) {
    cleanedData._cleaning.changes.push({
      field: 'timestamp',
      from: data.timestamp,
      to: cleanedData.timestamp,
      reason: '标准化为ISO 8601格式'
    });
  }

  if (data.deviceId !== cleanedData.deviceId) {
    cleanedData._cleaning.changes.push({
      field: 'deviceId',
      from: data.deviceId,
      to: cleanedData.deviceId,
      reason: '转大写并去除空格'
    });
  }

  cleaned.push({ json: cleanedData });
}

return cleaned;

// 质量评分节点
const items = $input.all();
const scored = [];

for (const item of items) {
  const data = item.json;

  // 计算质量分数
  let score = 1.0;

  // 完整性检查 (25%)
  const completeness = data.deviceId && data.timestamp && data.data ? 1.0 : 0.5;

  // 准确性检查 (35%) - 基于清洗置信度
  const accuracy = data._cleaning?.confidence || 0.8;

  // 一致性检查 (20%)
  const consistency = 1.0;

  // 置信度 (20%)
  const confidence = data._cleaning?.confidence || 0.8;

  const qualityScore = (
    completeness * 0.25 +
    accuracy * 0.35 +
    consistency * 0.20 +
    confidence * 0.20
  );

  scored.push({
    json: {
      ...data,
      _quality: {
        overall_score: qualityScore,
        breakdown: {
          completeness,
          accuracy,
          consistency,
          confidence
        },
        need_review: qualityScore < 0.7,
        review_reason: qualityScore < 0.7 ? '质量评分低于阈值' : null
      }
    }
  });
}

return scored;

// 模拟数据库写入
const items = $input.all();
const results = [];

for (const item of items) {
  results.push({
    json: {
      success: true,
      message: '数据已保存到数据库',
      data: item.json,
      savedAt: new Date().toISOString()
    }
  });
}

return results;

// 模拟推送到复核队列
const items = $input.all();
const results = [];

for (const item of items) {
  results.push({
    json: {
      task_id: `review-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
      created_at: new Date().toISOString(),
      data: {
        original: item.json,
        quality_score: item.json._quality?.overall_score,
        review_reason: item.json._quality?.review_reason
      },
      status: 'pending'
    }
  });
}

return results;

// 模拟错误日志记录
const items = $input.all();
const results = [];

for (const item of items) {
  results.push({
    json: {
      error: true,
      message: 'Schema验证失败',
      data: item.json,
      validation_errors: item.json._validation?.errors || [],
      timestamp: new Date().toISOString()
    }
  });
}

return results;
